SELECT COUNT(S.PK_SIAPE) AS QUANTIDADE FROM SERVIDOR S WHERE LOWER(COALESCE(S.CONTRATO,'')) = 'efetivos' AND LOWER(COALESCE(S.AREA_INGRESSO,'')) LIKE '%geografia%' AND LOWER(COALESCE(S.SIGLA_CAMPUS,'')) = 'luz' AND S.SAIU_DO_IFG = FALSE AND (S.DATA_INGRESSO_IFG IS NULL OR S.DATA_INGRESSO_IFG <= '2023-06-30')